+/** Record a target-specific relation event for pair tracking modifiers. */
+export function setPairTracking(
+    world: World,
+    entity: Entity,
+    trait: Trait,
+    target: Entity,
+    eventType: 'add' | 'remove' | 'change'
+) {
+    const data = getTraitInstance(world[$internal].traitInstances, trait);
+    if (!data) return;
+    const eid = getEntityId(entity);
+
+    for (const query of data.trackingQueries) {
+        let touched = false;
+        for (const group of query.trackingGroups) {
+            if (!group.pairs.length) continue;
+            for (let i = 0; i < group.pairs.length; i++) {
+                const pair = group.pairs[i];
+                const pairCtx = pair[$internal];
+                if (pairCtx.relation[$internal].trait !== trait) continue;
+                if (pairCtx.target !== '*' && pairCtx.target !== target) continue;
+                touched = true;
+                let targets = group.pairTrackers.get(i);
+                if (!targets) group.pairTrackers.set(i, (targets = new Map()));
+                let sources = targets.get(target);
+                if (!sources) targets.set(target, (sources = new Set()));
+                if (group.type === eventType) sources.add(eid);
+                else if ((eventType === 'add' && group.type !== 'add') || (eventType === 'remove' && group.type !== 'remove')) sources.delete(eid);
+            }
+        }
+        if (!touched) continue;
+
+        const matchesPairs = query.trackingGroups.every((group) => {
+            if (!group.pairs.length) return true;
+            const pairMatches = group.pairs.map((_, index) => {
+                const targets = group.pairTrackers.get(index);
+                return !!targets && Array.from(targets.values()).some((sources) => sources.has(eid));
+            });
+            return group.logic === 'and' ? pairMatches.every(Boolean) : pairMatches.some(Boolean);
+        });
+        const matches = matchesPairs && query.checkTracking(world, entity, eventType, data.generationId, data.bitflag);
+        if (matches) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
